import subprocess

def install_requirements():
    try:
        # Upgrade pip to the latest version
        subprocess.run(['pip', 'install', '--upgrade', 'pip'], check=True)
        
        # Install all requirements from requirements.txt without hash verification and upgrade them to the latest version
        subprocess.run(['pip', 'install', '-r', 'requirements.txt', '--no-cache-dir', '--upgrade', '--ignore-installed'], check=True)
        
        print("All dependencies installed successfully.")
    except subprocess.CalledProcessError as e:
        print(f"An error occurred: {e}")

if __name__ == "__main__":
    install_requirements()